import { motion } from 'framer-motion';
import { ShoppingBag } from 'lucide-react';
import { useCart } from '../contexts/CartContext';

export default function ArtworkCard({ artwork }) {
    const { addToCart } = useCart();

    return (
        <motion.div
            whileHover={{ y: -8, scale: 1.01 }}
            transition={{ type: "spring", stiffness: 400, damping: 25 }}
            className="bg-[#FFFCF9] rounded-sm shadow-md hover:shadow-2xl border border-[#E9DAC1] overflow-hidden flex flex-col group transition-shadow duration-500"
        >
            <div className="relative h-80 overflow-hidden bg-primary-100/50 p-2">
                {/* Ornate inner border effect */}
                <div className="absolute inset-2 border-2 border-[#CFAF65]/40 opacity-0 group-hover:opacity-100 transition-opacity duration-500 z-20 pointer-events-none"></div>

                <div className="absolute inset-0 bg-gradient-to-t from-primary-900/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 z-10"></div>

                {/* Image Display */}
                <div className="w-full h-full relative">
                    {artwork.imageUrl ? (
                        <img src={artwork.imageUrl} alt={artwork.title} className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-700 ease-out" />
                    ) : (
                        <div className="w-full h-full flex items-center justify-center p-4 text-primary-900/40 font-serif italic text-center bg-primary-100">
                            [Image of {artwork.title}]
                        </div>
                    )}
                </div>
            </div>

            <div className="p-6 flex flex-col flex-grow relative">
                <div className="absolute top-0 right-6 -translate-y-1/2 bg-accent-500 text-white text-[10px] uppercase font-bold tracking-[0.2em] px-3 py-1 shadow-md">
                    {artwork.category}
                </div>

                <h3 className="text-2xl font-bold text-primary-900 mb-2 mt-2 leading-tight">{artwork.title}</h3>

                {/* Subtle decorative line */}
                <div className="w-12 h-0.5 bg-accent-400 mb-4"></div>

                <p className="text-primary-800/80 text-sm mb-8 flex-grow leading-relaxed font-sans">{artwork.description}</p>

                <div className="flex items-center justify-between mt-auto">
                    <span className="text-xl font-bold text-accent-500">{artwork.price}</span>
                    <button
                        onClick={() => addToCart(artwork)}
                        className="flex items-center space-x-2 bg-primary-900 text-[#F3E5D8] px-4 py-2 hover:bg-accent-500 hover:text-white transition-colors duration-300"
                    >
                        <ShoppingBag className="w-4 h-4" />
                        <span className="text-sm font-semibold tracking-wide uppercase">Add to Cart</span>
                    </button>
                </div>
            </div>
        </motion.div>
    );
}

import { motion, AnimatePresence } from 'framer-motion';
import { X, Minus, Plus, ShoppingBag, Mail } from 'lucide-react';
import { useCart } from '../contexts/CartContext';

export default function CartDrawer() {
    const { isCartOpen, toggleCart, cartItems, removeFromCart, updateQuantity } = useCart();

    // Helper to calculate numeric total safely
    const calculateTotal = () => {
        return cartItems.reduce((total, item) => {
            // Assume price is a string like "Γé╣5,000" or "$200".
            // Strip non-numeric characters for a naive sum.
            const numericPrice = parseFloat(item.price.replace(/[^0-9.-]+/g, ""));
            return total + (numericPrice * item.quantity);
        }, 0);
    };

    const handleInquireAll = () => {
        if (cartItems.length === 0) return;

        let bodyText = `Namaste Rangitva,\n\nI would like to inquire about purchasing the following items from my cart:\n\n`;

        cartItems.forEach(item => {
            bodyText += `- ${item.title} (x${item.quantity}) - ${item.price} each\n`;
        });

        // Simple currency formatter attached to a generic number
        bodyText += `\nEstimated Total: Γé╣${calculateTotal().toLocaleString('en-IN')}\n\nPlease let me know the payment and delivery details.\n\nThank you!`;

        const subject = encodeURIComponent(`Purchase Inquiry: ${cartItems.length} items`);
        const body = encodeURIComponent(bodyText);

        window.location.href = `mailto:contact@rangitva.com?subject=${subject}&body=${body}`;
    };

    return (
        <AnimatePresence>
            {isCartOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={toggleCart}
                        className="fixed inset-0 bg-primary-900/40 backdrop-blur-sm z-50"
                    />

                    {/* Drawer */}
                    <motion.div
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                        className="fixed top-0 right-0 w-full sm:w-96 h-full bg-[#FFFCF9] shadow-2xl z-50 flex flex-col border-l border-[#E9DAC1]"
                    >
                        {/* Header */}
                        <div className="px-6 py-5 border-b border-[#E9DAC1] flex items-center justify-between bg-white">
                            <h2 className="text-xl font-serif font-bold text-primary-900 flex items-center">
                                <ShoppingBag className="w-5 h-5 mr-2 text-accent-500" />
                                Your Selection
                            </h2>
                            <button onClick={toggleCart} className="text-primary-600 hover:text-accent-500 transition-colors p-1">
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        {/* Cart Items List */}
                        <div className="flex-1 overflow-y-auto p-6 space-y-6">
                            {cartItems.length === 0 ? (
                                <div className="h-full flex flex-col items-center justify-center text-primary-600/60 opacity-70">
                                    <ShoppingBag className="w-16 h-16 mb-4" strokeWidth={1} />
                                    <p className="font-serif italic text-lg text-center">Your canvas is empty.</p>
                                </div>
                            ) : (
                                <AnimatePresence mode="popLayout">
                                    {cartItems.map((item) => (
                                        <motion.div
                                            key={item.id}
                                            layout
                                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                                            animate={{ opacity: 1, scale: 1, y: 0 }}
                                            exit={{ opacity: 0, scale: 0.8, x: 20 }}
                                            className="flex gap-4 p-3 border border-[#E9DAC1] bg-white shadow-sm"
                                        >
                                            {/* Thumbnail */}
                                            <div className="w-20 h-20 bg-primary-50 shrink-0 overflow-hidden relative">
                                                {item.imageUrl ? (
                                                    <img src={item.imageUrl} alt={item.title} className="w-full h-full object-cover" />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center bg-primary-100 text-[10px] text-primary-400 font-serif italic text-center p-1">No Image</div>
                                                )}
                                            </div>

                                            {/* Details */}
                                            <div className="flex-1 flex flex-col">
                                                <div className="flex justify-between items-start">
                                                    <h3 className="font-bold text-primary-900 text-sm leading-tight pr-2">{item.title}</h3>
                                                    <button onClick={() => removeFromCart(item.id)} className="text-primary-400 hover:text-red-500 transition-colors">
                                                        <X className="w-4 h-4" />
                                                    </button>
                                                </div>
                                                <p className="text-accent-500 font-bold text-sm mt-1">{item.price}</p>

                                                {/* Quantity Control */}
                                                <div className="mt-auto flex items-center space-x-3 bg-primary-50 w-fit px-2 py-1 border border-primary-100">
                                                    <button
                                                        onClick={() => updateQuantity(item.id, item.quantity - 1)}
                                                        className="text-primary-600 hover:text-accent-500 transition-colors p-0.5"
                                                    >
                                                        <Minus className="w-3 h-3" />
                                                    </button>
                                                    <span className="text-xs font-bold text-primary-900 w-4 text-center">{item.quantity}</span>
                                                    <button
                                                        onClick={() => updateQuantity(item.id, item.quantity + 1)}
                                                        className="text-primary-600 hover:text-accent-500 transition-colors p-0.5"
                                                    >
                                                        <Plus className="w-3 h-3" />
                                                    </button>
                                                </div>
                                            </div>
                                        </motion.div>
                                    ))}
                                </AnimatePresence>
                            )}
                        </div>

                        {/* Footer (Subtotal / Inquire Action) */}
                        {cartItems.length > 0 && (
                            <div className="border-t border-[#E9DAC1] bg-white p-6 shadow-[0_-4px_15px_-5px_rgba(0,0,0,0.05)]">
                                <div className="flex justify-between items-center mb-6">
                                    <span className="text-primary-800 font-medium">Estimated Total</span>
                                    <span className="text-2xl font-bold text-primary-900">Γé╣{calculateTotal().toLocaleString('en-IN')}</span>
                                </div>
                                <button
                                    onClick={handleInquireAll}
                                    className="w-full flex justify-center items-center py-4 px-4 border border-transparent text-sm font-bold text-white bg-primary-900 hover:bg-accent-500 focus:outline-none transition-colors uppercase tracking-widest shadow-md"
                                >
                                    <Mail className="w-4 h-4 mr-2" />
                                    Inquire About Cart
                                </button>
                                <p className="text-xs text-center text-primary-400 mt-3 font-serif italic">This will open your email client.</p>
                            </div>
                        )}
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
}

