                >
                    <svg viewBox="0 0 100 100" fill="#A72814"><path d="M50 0 C55 40, 90 45, 100 50 C90 55, 55 60, 50 100 C45 60, 10 55, 0 50 C10 45, 45 40, 50 0 Z" /></svg>
